class Solution(object):
    def minValidStrings(self, words, target):
        n = len(target)
        trie = {}
        for word in words:
            node = trie
            for c in word:
                if c not in node:
                    node[c] = {}
                node = node[c]

        dp = [float('inf')] * (n + 1)
        dp[0] = 0
        for i in range(n):
            if dp[i] == float('inf'):
                continue
            node = trie
            j = i
            while j < n and target[j] in node:
                node = node[target[j]]
                j += 1
                dp[j] = min(dp[j], dp[i] + 1)

        return dp[n] if dp[n] != float('inf') else -1
